eventScript.func:
let winHash = window.location.hash || '';
if (winHash.indexOf('flowLibrary/formFlow') > -1) return;
const initiatorCompanyId = this.getValue('initiatorCompanyId') || window.localStorage.getItem('invest-power-system-companyId') || '';
const companyName = this.getValue('companyName') || window.localStorage.getItem('invest-power-system-companyName') || '';
let currentValue = this.getValue('originContractObj');
let parsedValue = {};
try {
  parsedValue = currentValue ? JSON.parse(currentValue) : {};
} catch (error) {
  parsedValue = {};
}
if (!parsedValue || Array.isArray(parsedValue)) {
  parsedValue = {};
}
if (!parsedValue.initiatorCompanyId || !parsedValue.companyName) {
  this.setData({
    originContractObj: JSON.stringify(Object.assign({}, parsedValue, {
      initiatorCompanyId: initiatorCompanyId,
      companyName: companyName,
    }))
  });
}
this.triggerEvent('syncOriginContractInfo');
this.triggerEvent('toggleMainBodyMode', this.getValue('mainBodyRadio') || '手动填写');
this.triggerEvent('syncChangedAmountUpper');

function pick() {
  for (var i = 0; i < arguments.length; i += 1) {
    var item = arguments[i];
    if (item !== undefined && item !== null && item !== '') {
      return item;
    }
  }
  return '';
}
function capitalMoney(num) {
  if (num === undefined || num === null || num === '') return '';
  num = String(num).replace(/,/g, '');
  if (isNaN(Number(num))) return '';
  var strOutput = '';
  var strUnit = '仟佰拾亿仟佰拾万仟佰拾元角分';
  num += '00';
  var intPos = num.indexOf('.');
  if (intPos >= 0) {
    num = num.substring(0, intPos) + num.substr(intPos + 1, 2);
  }
  strUnit = strUnit.substr(strUnit.length - num.length);
  for (var i = 0; i < num.length; i += 1) {
    strOutput += '零壹贰叁肆伍陆柒捌玖'.substr(num.substr(i, 1), 1) + strUnit.substr(i, 1);
  }
  return strOutput
    .replace(/零角零分$/, '整')
    .replace(/零[仟佰拾]/g, '零')
    .replace(/零{2,}/g, '零')
    .replace(/零([亿|万])/g, '$1')
    .replace(/零+元/, '元')
    .replace(/亿零{0,3}万/, '亿')
    .replace(/^元/, '零元');
}
function normalizeContractTalk(value) {
  if (value === undefined || value === null || value === '') return '';
  let raw = String(value).trim();
  let map = {
    'open': '公开招标',
    'openBid': '公开招标',
    'publicBidding': '公开招标',
    '公开招标': '公开招标',
    'invitation': '非公开挂网',
    '邀请招标': '非公开挂网',
    '非公开挂网': '非公开挂网',
    'inquiry': '非挂网方式',
    'negotiations': '非挂网方式',
    'consult': '非挂网方式',
    '询比采购': '非挂网方式',
    '竞争性谈判采购': '非挂网方式',
    '竞争性磋商采购': '非挂网方式',
    '非挂网方式': '非挂网方式',
    'direct': '直签',
    'directSign': '直签',
    '直签': '直签',
    'singleSource': '单一来源采购',
    'single_source': '单一来源采购',
    '单一来源采购': '单一来源采购',
    'internal': '内部采购',
    'internalPurchase': '内部采购',
    '内部采购': '内部采购',
    'framework': '框采',
    '框架协议采购': '框采',
    '框采': '框采',
    'other': '其他',
    '其他': '其他'
  };
  return map[raw] || raw;
}
let parsedValue = {};
try {
  parsedValue = JSON.parse(this.getValue('originContractObj') || '{}');
} catch (error) {
  parsedValue = {};
}
let rowData = {};
try {
  rowData = parsedValue.rowData ? JSON.parse(parsedValue.rowData) : {};
} catch (error) {
  rowData = {};
}
let originContractSyncKey = pick(parsedValue.id, parsedValue.contractId, parsedValue.bizId, rowData.id, rowData.contractId, rowData.bizId, rowData.flowProxyId, '');
let cachedSyncKey = this.getValue('originContractSyncKey') || '';
let originAmount = pick(
  rowData.contractSum,
  rowData.contractAmount,
  rowData.contractMoney,
  rowData.amount,
  parsedValue.contractSum,
  ''
);
let originSubject = pick(
  rowData.newContractBody,
  rowData.contractBodyName,
  rowData.contractMainBody,
  rowData.contractBody,
  parsedValue.newContractBody,
  ''
);
let originTalkWay = normalizeContractTalk(pick(
  rowData.contractTalk,
  rowData.contractTalkName,
  rowData.procureWay,
  rowData.procureWayName,
  rowData.negotiationMethod,
  rowData.negotiationWay,
  rowData.contractNegotiationMethod,
  rowData.contractNegotiationWay,
  parsedValue.contractTalk,
  parsedValue.contractTalkName,
  parsedValue.procureWay,
  parsedValue.procureWayName,
  parsedValue.negotiationMethod,
  parsedValue.negotiationWay,
  parsedValue.contractNegotiationMethod,
  parsedValue.contractNegotiationWay,
  ''
));
let nextData = {
  originContractSyncKey: originContractSyncKey,
  originProjectName: pick(rowData.projectName, rowData.contractProjectName, parsedValue.projectName, ''),
  originContractSubject: originSubject,
  originContractCategory: pick(rowData.classificationName, rowData.contractCategoryName, rowData.contractCategory, parsedValue.classificationName, ''),
  originContractTalkWay: originTalkWay,
  originContractAmount: originAmount,
  originContractAmountUpper: capitalMoney(originAmount)
};
if (originContractSyncKey && originContractSyncKey !== cachedSyncKey) {
  nextData.contractTalk = originTalkWay || '';
} else if (!this.getValue('contractTalk') && originTalkWay) {
  nextData.contractTalk = originTalkWay;
}
this.setData(nextData);

