if (currentValue === '相关方') {
  this.display(['relatePartyReport']);
  this.hide(['mainBodySubform']);
  this.setData({ mainBodySubform: [{ partyType: '甲方', partyName: '' }, { partyType: '乙方', partyName: '' }] });
