dataSource.requestFunc:
let WHOST = window.location.host;
let host = '';
if (WHOST.indexOf('bserver') === 0) {
  host = 'https://iserver.runshihua.com';
} else {
  host = 'http://192.168.1.220:8081';
}
let sid = '';
for (const key in window.localStorage) {
  if (key.endsWith('invest-power-system-token')) {
    sid = window.localStorage.getItem(key);
  }
}
config.url = host + config.url + '&sid=' + sid;
config.data = { data: {}, sid: sid };
return config;
